def gen(rng, size):
    n = rng.randint(1, max(1, size))
    vals = rng.sample(range(1, 10000001), n)
    order = vals[:]
    rng.shuffle(order)
    root = None
    nodes = {}
    def insert(v):
        nonlocal root
        if root is None:
            root = v
            nodes[v] = [None, None]
            return
        cur = root
        while True:
            l, r = nodes[cur]
            if v < cur:
                if l is None:
                    nodes[cur][0] = v; nodes[v] = [None, None]; return
                cur = l
            else:
                if r is None:
                    nodes[cur][1] = v; nodes[v] = [None, None]; return
                cur = r
    for v in order:
        insert(v)
    out = []
    from collections import deque
    q = deque([root])
    while q:
        cur = q.popleft()
        if cur is None:
            out.append(None); continue
        out.append(cur)
        nodes_l, nodes_r = nodes[cur]
        q.append(nodes_l); q.append(nodes_r)
    while out and out[-1] is None:
        out.pop()
    if rng.random() < 0.5:
        target = rng.choice(vals)
    else:
        target = rng.randint(1, 10000000)
    return [out, target]

